import sys

def shortest_palindrome(s):
    n = len(s)
    if n == 0:
        return ""
    # Find the longest palindromic prefix
    l, r = 0, n - 1
    while l <= r:
        if s[l] == s[r]:
            l += 1
            r -= 1
        else:
            break
    # The substring from l to r is a palindrome
    # Add the reverse of the remaining part to the front
    return s + s[:l][::-1]

def main():
    s = sys.stdin.readline().strip()
    print(shortest_palindrome(s))

if __name__ == "__main__":
    main()
